import React, { useEffect, useMemo, useState } from 'react';
import { createClient } from '@supabase/supabase-js';
import { AlertTriangle, Boxes, CalendarDays, CheckCircle2, ClipboardList, Copy, Database, Download, Maximize2, Minimize2, Package, Plus, RotateCw, Trash2, Wind } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';

const POSITIONS = [1,2,3,4,5,6,7,8];
const STORAGE_KEY = 'buzzfly_bsf_multi_container_daily_reviews_v5_online';
const SUPABASE_STATE_ID = 'buzzfly-bsf-main';
const SUPABASE_URL = import.meta.env?.VITE_SUPABASE_URL || '';
const SUPABASE_ANON_KEY = import.meta.env?.VITE_SUPABASE_ANON_KEY || '';
const supabase = SUPABASE_URL && SUPABASE_ANON_KEY ? createClient(SUPABASE_URL, SUPABASE_ANON_KEY) : null;

const BRAND = { navy:'#07354A', text:'#12222B', muted:'#64727A', line:'#DDE5E8', soft:'#F6F8F9', softBlue:'#EEF5F8', ok:'#2F7D4D', warn:'#C98716', danger:'#B83232', empty:'#8A96A0', crateBlue:'#1685C0', crateBlack:'#252D33', pallet:'#C9B89E', palletDark:'#9A876E' };
const DEFAULT_CONTAINERS = Array.from({ length: 17 }, (_, i) => ({ id:`CT-${i+1}`, number:String(i+1), name:`CT ${i+1}` }));

function todayISO(){ return new Date().toISOString().slice(0,10); }
function formatDateBR(v){ if(!v) return '-'; const [y,m,d]=v.split('-'); return `${d}/${m}/${y}`; }
function emptyPosition(position){ return { position, lote:'', caixas:'', dieta:'', dietaKgPorCaixa:'', uso:'Produção', status:'OK', observacoes:'' }; }
function emptyContainerReview(c){ return { containerId:c.id, ct:c.number, name:c.name, ventilacao:'Manual', recirculacao:'OFF', setpoint:'', observacoesGerais:'', positions: POSITIONS.map(emptyPosition) }; }
function makeDayReview(date, containers){ return { id: crypto.randomUUID(), date, responsavel:'', containers: containers.map(emptyContainerReview), createdAt:new Date().toISOString(), updatedAt:new Date().toISOString() }; }
function loadLocal(){ try { const s=JSON.parse(localStorage.getItem(STORAGE_KEY)||'null'); if(s?.containers?.length && Array.isArray(s.dailyReviews)) return s; } catch{} const init={containers:DEFAULT_CONTAINERS,dailyReviews:[]}; localStorage.setItem(STORAGE_KEY,JSON.stringify(init)); return init; }
function persistLocal(s){ localStorage.setItem(STORAGE_KEY, JSON.stringify(s)); }
async function loadStateOnline(){ if(!supabase) return loadLocal(); const local=loadLocal(); const {data,error}=await supabase.from('app_state').select('data').eq('id',SUPABASE_STATE_ID).maybeSingle(); if(error){ console.error(error); return local; } if(data?.data?.containers?.length){ persistLocal(data.data); return data.data; } await supabase.from('app_state').upsert({ id:SUPABASE_STATE_ID, data:local, updated_at:new Date().toISOString() }); return local; }
async function saveStateOnline(s){ persistLocal(s); if(!supabase) return; const {error}=await supabase.from('app_state').upsert({ id:SUPABASE_STATE_ID, data:s, updated_at:new Date().toISOString() }); if(error) throw error; }
function clonePreviousDayReview(prev, targetDate, containers){ const map=new Map(prev.containers.map(c=>[c.containerId,c])); return { id: crypto.randomUUID(), date: targetDate, responsavel: prev.responsavel||'', containers: containers.map(c=> map.get(c.id) ? {...JSON.parse(JSON.stringify(map.get(c.id))), ct:c.number, name:c.name} : emptyContainerReview(c)), createdAt:new Date().toISOString(), updatedAt:new Date().toISOString(), clonedFrom: prev.date }; }
function computeContainerTotals(c){ return c.positions.reduce((a,p)=>{ const caixas=Number(p.caixas)||0; const kg=Number(p.dietaKgPorCaixa)||0; const emUso=p.uso!=='Vazio' && p.status!=='Vazio' && (caixas>0 || p.lote); a.boxes+=caixas; a.dietKg+=caixas*kg; if(emUso) a.filled+=1; if(p.status==='Crítico') a.critical+=1; if(p.status==='Atenção') a.attention+=1; if(p.status==='OK') a.ok+=1; if(p.status==='Vazio') a.empty+=1; if(['Produção','Engorda','Colônia'].includes(p.uso)){ a.fatteningBoxes+=caixas; if(emUso) a.fatteningPositions+=1; } if(p.uso==='Maternidade'){ a.maternityBoxes+=caixas; if(emUso) a.maternityPositions+=1; } if(p.uso==='Colônia'){ a.colonyBoxes+=caixas; if(emUso) a.colonyPositions+=1; } return a; }, {boxes:0,dietKg:0,filled:0,critical:0,attention:0,ok:0,empty:0,fatteningBoxes:0,maternityBoxes:0,colonyBoxes:0,fatteningPositions:0,maternityPositions:0,colonyPositions:0}); }
function statusMeta(s){ if(s==='Crítico') return {bg:'#FDECEC', color:BRAND.danger, label:'Crítico'}; if(s==='Atenção') return {bg:'#FFF6DF',color:BRAND.warn,label:'Atenção'}; if(s==='Vazio') return {bg:'#F1F5F7',color:BRAND.empty,label:'Vazio'}; return {bg:'#EAF7EF',color:BRAND.ok,label:'OK'}; }
function useMeta(u){ if(u==='Maternidade') return {bg:'#FDEDF3',color:'#A64D6C',label:'Maternidade',icon:'🪱'}; if(u==='Colônia') return {bg:'#F1F3F5',color:'#1F2933',label:'Colônia',icon:'●'}; if(u==='Vazio') return {bg:'#F1F5F7',color:BRAND.empty,label:'Vazio',icon:'□'}; return {bg:'#FFF7D6',color:'#8A6A00',label:'Produção',icon:'🟡'}; }
function getContainerUseBadges(c){ const totals={Produção:0,Colônia:0,Maternidade:0}; c.positions.forEach(p=>{ const cx=Number(p.caixas)||0; if(cx<=0) return; if(p.uso==='Maternidade') totals.Maternidade+=cx; else if(p.uso==='Colônia') totals.Colônia+=cx; else if(p.uso==='Produção'||p.uso==='Engorda') totals.Produção+=cx; }); const arr=Object.entries(totals).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]).slice(0,2).map(([k])=>useMeta(k)); return arr.length?arr:[useMeta('Vazio')]; }

function BuzzLogo(){ return <div className="flex items-end gap-3 select-none"><span className="text-4xl md:text-5xl font-light tracking-[0.38em]" style={{color:BRAND.navy}}>BUZZ</span><span className="text-lg md:text-xl font-light tracking-[0.24em] mb-1.5" style={{color:BRAND.navy}}>FLY</span></div>; }
function Metric({label,value,icon:Icon=ClipboardList,tone='default',sublabel=''}){ const p=tone==='danger'?{bg:'#FDECEC',color:BRAND.danger}:tone==='warn'?{bg:'#FFF6DF',color:BRAND.warn}:tone==='ok'?{bg:'#EAF7EF',color:BRAND.ok}:{bg:BRAND.softBlue,color:BRAND.navy}; return <div className="border rounded-xl p-3 bg-white flex items-center gap-3" style={{borderColor:BRAND.line}}><div className="h-10 w-10 rounded-xl flex items-center justify-center" style={{backgroundColor:p.bg,color:p.color}}><Icon className="h-5 w-5"/></div><div><p className="text-xs font-semibold" style={{color:BRAND.muted}}>{label}</p><p className="text-2xl font-semibold" style={{color:BRAND.text}}>{value}</p>{sublabel&&<p className="text-[11px] font-semibold" style={{color:BRAND.muted}}>{sublabel}</p>}</div></div>; }
function InfoChip({label, icon:Icon=ClipboardList, tone='default'}){ const color=tone==='danger'?BRAND.danger:BRAND.navy; const bg=tone==='danger'?'#FDECEC':BRAND.softBlue; return <span className="inline-flex items-center gap-1 rounded-full px-3 py-1 font-semibold" style={{backgroundColor:bg,color}}><Icon className="h-3.5 w-3.5"/>{label}</span>; }
function ControlSelect({label,value,onChange,options,muted=false}){ return <label className="space-y-1"><span className="text-sm font-semibold" style={{color:muted?BRAND.muted:BRAND.text}}>{label}</span><select value={value} onChange={e=>onChange(e.target.value)} className="w-full border rounded-xl px-3 py-2 bg-white" style={{borderColor:BRAND.line}}>{options.map(o=><option key={o}>{o}</option>)}</select></label>; }
function StatusPill({status, small=false}){ const m=statusMeta(status); return <span className={`inline-flex items-center gap-1 rounded-full font-semibold ${small?'px-2 py-0.5 text-[10px]':'px-3 py-1 text-xs'}`} style={{backgroundColor:m.bg,color:m.color}}>{status==='OK'?'✓':status==='Vazio'?'○':'!'} {m.label}</span>; }
function UsePill({uso,small=false}){ const m=useMeta(uso); return <span className={`inline-flex items-center gap-1.5 rounded-full font-semibold ${small?'px-2 py-0.5 text-[10px]':'px-3 py-1 text-xs'}`} style={{backgroundColor:m.bg,color:m.color}}><span>{m.icon}</span>{m.label}</span>; }
function StatusDot({status}){ return <span className="h-3 w-3 rounded-full" style={{backgroundColor:statusMeta(status).color}}/>; }

export default function BSFContainerReviewSystem(){
  const [state,setState]=useState({containers:DEFAULT_CONTAINERS,dailyReviews:[]});
  const [selectedDate,setSelectedDate]=useState(todayISO());
  const [selectedContainerId,setSelectedContainerId]=useState('CT-1');
  const [newContainerNumber,setNewContainerNumber]=useState('');
  const [selected3DPosition,setSelected3DPosition]=useState(null);
  const [activePage,setActivePage]=useState('gestao');
  const [lastResetBackup,setLastResetBackup]=useState(null);
  const [isLoading,setIsLoading]=useState(true);
  const [syncStatus,setSyncStatus]=useState(supabase?'Conectando ao Supabase...':'Modo local');

  useEffect(()=>{ let active=true; (async()=>{ setIsLoading(true); const loaded=await loadStateOnline(); if(!active) return; setState(loaded); setSelectedContainerId(loaded.containers?.[0]?.id||''); const latest=[...(loaded.dailyReviews||[])].sort((a,b)=>b.date.localeCompare(a.date))[0]; if(latest) setSelectedDate(latest.date); setSyncStatus(supabase?'Online · Supabase':'Modo local · sem Supabase'); setIsLoading(false); })(); return()=>{active=false}; },[]);
  const currentReview=useMemo(()=>state.dailyReviews.find(r=>r.date===selectedDate)||null,[state,selectedDate]);
  const latestReview=useMemo(()=>[...state.dailyReviews].sort((a,b)=>b.date.localeCompare(a.date))[0]||null,[state]);
  const selectedContainerReview=useMemo(()=>currentReview?.containers.find(c=>c.containerId===selectedContainerId)||currentReview?.containers[0]||null,[currentReview,selectedContainerId]);
  const dayTotals=useMemo(()=>{ if(!currentReview) return {boxes:0,dietKg:0,filledPositions:0,totalPositions:state.containers.length*8,occupancyRate:0,attention:0,critical:0,fatteningBoxes:0,maternityBoxes:0,colonyBoxes:0}; const t=currentReview.containers.reduce((a,c)=>{const x=computeContainerTotals(c); a.boxes+=x.boxes; a.dietKg+=x.dietKg; a.filledPositions+=x.filled; a.attention+=x.attention; a.critical+=x.critical; a.fatteningBoxes+=x.fatteningBoxes; a.maternityBoxes+=x.maternityBoxes; a.colonyBoxes+=x.colonyBoxes; return a;},{boxes:0,dietKg:0,filledPositions:0,totalPositions:currentReview.containers.length*8,occupancyRate:0,attention:0,critical:0,fatteningBoxes:0,maternityBoxes:0,colonyBoxes:0}); t.occupancyRate=t.totalPositions?Math.round(t.filledPositions/t.totalPositions*100):0; return t; },[currentReview,state.containers.length]);
  const selectedTotals=selectedContainerReview?computeContainerTotals(selectedContainerReview):{boxes:0,dietKg:0,critical:0,attention:0};

  function updateState(next){ setState(next); setSyncStatus(supabase?'Salvando...':'Modo local'); saveStateOnline(next).then(()=>setSyncStatus(supabase?'Online · salvo':'Modo local · salvo')).catch(e=>{console.error(e); setSyncStatus('Erro ao salvar online');}); }
  function updateDay(mutator){ if(!currentReview) return; const updated=state.dailyReviews.map(r=>{ if(r.id!==currentReview.id) return r; const n=JSON.parse(JSON.stringify(r)); mutator(n); n.updatedAt=new Date().toISOString(); return n; }); updateState({...state,dailyReviews:updated}); }
  function createEmptyDay(){ if(state.dailyReviews.find(r=>r.date===selectedDate)) return; const day=makeDayReview(selectedDate,state.containers); updateState({...state,dailyReviews:[day,...state.dailyReviews]}); setSelectedContainerId(state.containers[0]?.id||''); }
  function createDayFromPrevious(){ if(state.dailyReviews.find(r=>r.date===selectedDate)){ alert('Já existe revisão para esta data.'); return; } const prev=[...state.dailyReviews].filter(r=>r.date<selectedDate).sort((a,b)=>b.date.localeCompare(a.date))[0]; if(!prev){ alert('Não há revisão anterior para copiar.'); return; } const day=clonePreviousDayReview(prev,selectedDate,state.containers); updateState({...state,dailyReviews:[day,...state.dailyReviews]}); }
  function deleteDay(date){ if(confirm(`Excluir a revisão do dia ${formatDateBR(date)}?`)) updateState({...state,dailyReviews:state.dailyReviews.filter(r=>r.date!==date)}); }
  function updateResponsible(v){ updateDay(d=>{d.responsavel=v;}); }
  function updateContainerField(f,v){ updateDay(d=>{ const c=d.containers.find(x=>x.containerId===selectedContainerId); if(c) c[f]=v; }); }
  function updatePosition(idx,field,value){ updateDay(d=>{ const c=d.containers.find(x=>x.containerId===selectedContainerId); if(!c) return; if(field==='caixas'){ const max=c.positions[idx].uso==='Maternidade'?150:15; if(value==='') c.positions[idx].caixas=''; else c.positions[idx].caixas=String(Math.max(0,Math.min(max,Number(value)||0))); return; } c.positions[idx][field]=value; if(field==='uso'){ const max=value==='Maternidade'?150:15; const parsed=Number(c.positions[idx].caixas); if(!Number.isNaN(parsed)&&parsed>max) c.positions[idx].caixas=String(max); } if((field==='status'&&value==='Vazio')||(field==='uso'&&value==='Vazio')) Object.assign(c.positions[idx],{uso:'Vazio',status:'Vazio',lote:'',caixas:'',dieta:'',dietaKgPorCaixa:''}); }); }
  function resetSelectedContainer(){ if(!currentReview||!selectedContainerId) return; const before=currentReview.containers.find(c=>c.containerId===selectedContainerId); setLastResetBackup({reviewId:currentReview.id,date:selectedDate,containerId:selectedContainerId,container:JSON.parse(JSON.stringify(before))}); updateDay(d=>{ const c=d.containers.find(x=>x.containerId===selectedContainerId); if(!c) return; c.observacoesGerais=''; c.positions=POSITIONS.map(position=>({position,lote:'',caixas:'0',dieta:'',dietaKgPorCaixa:'0',uso:'Vazio',status:'Vazio',observacoes:''})); }); setSelected3DPosition(null); }
  function undoResetSelectedContainer(){ if(!lastResetBackup||!currentReview) return; if(lastResetBackup.reviewId!==currentReview.id||lastResetBackup.containerId!==selectedContainerId){ alert('Reversão é de outro container/data.'); return; } updateDay(d=>{ const i=d.containers.findIndex(c=>c.containerId===selectedContainerId); if(i>=0) d.containers[i]=JSON.parse(JSON.stringify(lastResetBackup.container)); }); setLastResetBackup(null); }
  function addContainer(){ const number=newContainerNumber.trim(); if(!number) return; const c={id:`CT-${number}-${Date.now()}`,number,name:`CT ${number}`}; updateState({containers:[...state.containers,c],dailyReviews:state.dailyReviews.map(d=>({...d,containers:[...d.containers,emptyContainerReview(c)]}))}); setSelectedContainerId(c.id); setNewContainerNumber(''); }
  function removeContainer(id){ if(!confirm('Remover este container do sistema e históricos?')) return; const cs=state.containers.filter(c=>c.id!==id); updateState({containers:cs,dailyReviews:state.dailyReviews.map(d=>({...d,containers:d.containers.filter(c=>c.containerId!==id)}))}); setSelectedContainerId(cs[0]?.id||''); }
  function generatePDF(){ const source=document.getElementById('daily-report')||document.getElementById('daily-report-pdf'); if(!source){ alert('Relatório não encontrado.'); return; } const styles=Array.from(document.querySelectorAll('style,link[rel="stylesheet"]')).map(n=>n.outerHTML).join('\n'); const w=window.open('','_blank','width=1200,height=900'); if(!w){ alert('Permita pop-ups para exportar o PDF.'); return; } w.document.write(`<!doctype html><html><head><meta charset="utf-8"/><title>Relatório Buzz Fly</title>${styles}<style>@page{size:A4 portrait;margin:8mm}*{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;box-sizing:border-box}body{margin:0;background:#fff!important;font-family:ui-sans-serif,system-ui}.break-inside-avoid{break-inside:avoid;page-break-inside:avoid}tr{break-inside:avoid;page-break-inside:avoid}</style></head><body>${source.outerHTML}<script>window.onload=function(){setTimeout(function(){window.focus();window.print()},350)}<\/script></body></html>`); w.document.close(); }
  function exportJSON(){ const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}); const url=URL.createObjectURL(blob); const a=document.createElement('a'); a.href=url; a.download=`backup-buzzfly-bsf-${todayISO()}.json`; a.click(); URL.revokeObjectURL(url); }
  function importJSON(){ const input=document.createElement('input'); input.type='file'; input.accept='application/json,.json'; input.onchange=async e=>{ const file=e.target.files?.[0]; if(!file) return; try{ const imported=JSON.parse(await file.text()); if(!imported?.containers?.length||!Array.isArray(imported.dailyReviews)) throw new Error('invalid'); updateState(imported); const latest=[...imported.dailyReviews].sort((a,b)=>b.date.localeCompare(a.date))[0]; if(latest){setSelectedDate(latest.date); setSelectedContainerId(latest.containers?.[0]?.containerId||imported.containers[0]?.id||'');} alert('Backup importado com sucesso.'); }catch{alert('JSON inválido.');}}; input.click(); }

  return <div className="min-h-screen p-4 md:p-8" style={{backgroundColor:BRAND.soft,color:BRAND.text}}><div className="mx-auto max-w-7xl space-y-6">{isLoading&&<Card className="rounded-[1.25rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-4 text-sm font-semibold" style={{color:BRAND.muted}}>Carregando dados online...</CardContent></Card>}
    <header className="rounded-[1.75rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><div className="p-5 md:p-7"><div className="flex flex-col xl:flex-row xl:items-center xl:justify-between gap-5"><div className="space-y-4"><BuzzLogo/><div><h1 className="text-2xl md:text-3xl font-semibold tracking-tight">Sistema de Gestão e Controle da Criação - BSF</h1><p className="text-sm md:text-base" style={{color:BRAND.muted}}>Controle geral dos containers de criação - BSF.</p></div></div><div className="flex flex-wrap gap-2"><span className="inline-flex items-center rounded-xl border px-3 py-2 text-sm font-semibold" style={{borderColor:BRAND.line,color:supabase?BRAND.ok:BRAND.warn}}><Database className="h-4 w-4 mr-2"/>{syncStatus}</span><Button variant="outline" onClick={exportJSON} className="rounded-xl"><Database className="h-4 w-4 mr-2"/>Backup</Button><Button variant="outline" onClick={importJSON} className="rounded-xl"><Database className="h-4 w-4 mr-2"/>Importar backup</Button><Button onClick={generatePDF} disabled={!currentReview} className="rounded-xl text-white" style={{backgroundColor:BRAND.navy}}><Download className="h-4 w-4 mr-2"/>PDF dos containers</Button></div></div></div></header>
    <Card className="rounded-[1.25rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-3 flex flex-col md:flex-row md:items-center md:justify-between gap-3"><div><p className="text-xs font-semibold uppercase tracking-[0.18em]" style={{color:BRAND.muted}}>navegação</p><h2 className="text-lg font-semibold">Fluxo do sistema</h2></div><div className="flex flex-wrap gap-2"><button onClick={()=>setActivePage('gestao')} className="rounded-xl px-4 py-2 text-sm font-semibold" style={{backgroundColor:activePage==='gestao'?BRAND.navy:'#fff',color:activePage==='gestao'?'#fff':BRAND.text,border:`1px solid ${activePage==='gestao'?BRAND.navy:BRAND.line}`}}>Página 1 · Gestão / Preenchimento</button><button onClick={()=>setActivePage('relatorio')} className="rounded-xl px-4 py-2 text-sm font-semibold" style={{backgroundColor:activePage==='relatorio'?BRAND.navy:'#fff',color:activePage==='relatorio'?'#fff':BRAND.text,border:`1px solid ${activePage==='relatorio'?BRAND.navy:BRAND.line}`}}>Página 2 · Relatório</button></div></CardContent></Card>
    {activePage==='gestao' && <><Card className="rounded-[1.5rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-5 space-y-4"><div className="grid grid-cols-1 md:grid-cols-5 gap-4 items-end"><label className="space-y-1"><span className="text-sm font-semibold">Data operacional</span><input type="date" value={selectedDate} onChange={e=>setSelectedDate(e.target.value)} className="w-full border rounded-xl px-3 py-2 bg-white" style={{borderColor:BRAND.line}}/></label><div className="md:col-span-2 flex flex-wrap gap-2"><Button onClick={createEmptyDay} variant="outline" className="rounded-xl"><CalendarDays className="h-4 w-4 mr-2"/>Criar dia vazio</Button><Button onClick={createDayFromPrevious} className="rounded-xl text-white" style={{backgroundColor:BRAND.navy}}><Copy className="h-4 w-4 mr-2"/>Copiar última data</Button></div><label className="space-y-1 md:col-span-2"><span className="text-sm font-semibold">Responsável pela revisão</span><input disabled={!currentReview} value={currentReview?.responsavel||''} onChange={e=>updateResponsible(e.target.value)} className="w-full border rounded-xl px-3 py-2 bg-white disabled:bg-slate-100" style={{borderColor:BRAND.line}}/></label></div>{!currentReview&&<p className="text-sm rounded-xl p-3" style={{backgroundColor:'#FFF8E8',border:'1px solid #F0DCA6',color:'#6B4A00'}}>Crie um dia vazio ou copie a última data.</p>}{currentReview&&<div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-8 gap-3 text-sm"><Metric label="Containers" value={currentReview.containers.length}/><Metric label="Ocupação" value={`${dayTotals.occupancyRate}%`} icon={Package} tone="ok" sublabel={`${dayTotals.filledPositions}/${dayTotals.totalPositions} posições`}/><Metric label="Caixas totais" value={dayTotals.boxes} icon={Boxes}/><Metric label="Dieta em bioconversão" value={`${dayTotals.dietKg.toFixed(1)} kg`} icon={Package}/><Metric label="Caixas engorda" value={dayTotals.fatteningBoxes} icon={Boxes}/><Metric label="Caixas maternidade" value={dayTotals.maternityBoxes} icon={Boxes}/><Metric label="Atenção" value={dayTotals.attention} icon={AlertTriangle} tone="warn"/><Metric label="Críticas" value={dayTotals.critical} icon={AlertTriangle} tone="danger"/></div>}</CardContent></Card>{latestReview&&<ContainerYardOverview review={latestReview} selectedContainerId={selectedContainerId} onSelectContainer={(id)=>{setSelectedDate(latestReview.date);setSelectedContainerId(id);setSelected3DPosition(null)}}/>}<div className="grid grid-cols-1 lg:grid-cols-4 gap-6"><aside className="space-y-6"><Card className="rounded-[1.5rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-5 space-y-4"><div className="flex items-center justify-between"><h2 className="text-lg font-semibold">Containers</h2><span className="text-xs font-semibold px-2 py-1 rounded-full" style={{backgroundColor:BRAND.softBlue,color:BRAND.navy}}>{state.containers.length} CTs</span></div><div className="flex gap-2"><input value={newContainerNumber} onChange={e=>setNewContainerNumber(e.target.value)} placeholder="Novo CT" className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/><Button onClick={addContainer} className="rounded-xl text-white" style={{backgroundColor:BRAND.navy}}><Plus className="h-4 w-4"/></Button></div><div className="space-y-2 max-h-[420px] overflow-auto pr-1">{state.containers.map(c=>{const active=selectedContainerId===c.id; const dc=currentReview?.containers.find(x=>x.containerId===c.id); const t=dc?computeContainerTotals(dc):null; return <div key={c.id} className="border rounded-xl p-2 flex items-center gap-2 bg-white" style={{borderColor:active?BRAND.navy:BRAND.line}}><button onClick={()=>setSelectedContainerId(c.id)} className="flex-1 text-left px-2 py-1"><div className="font-semibold" style={{color:active?BRAND.navy:BRAND.text}}>{c.name}</div>{t&&<p className="text-[11px]" style={{color:BRAND.muted}}>{t.boxes} cx · {t.attention} atenção · {t.critical} crítico</p>}</button><button onClick={()=>removeContainer(c.id)} className="p-2 rounded-lg hover:bg-red-50 text-red-600"><Trash2 className="h-4 w-4"/></button></div>})}</div></CardContent></Card><Card className="rounded-[1.5rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-5 space-y-4"><h2 className="text-lg font-semibold">Histórico diário</h2><div className="space-y-2 max-h-[360px] overflow-auto pr-1">{[...state.dailyReviews].sort((a,b)=>b.date.localeCompare(a.date)).map(r=><div key={r.id} className="border rounded-xl p-3 bg-white" style={{borderColor:r.date===selectedDate?BRAND.navy:BRAND.line}}><div className="flex justify-between"><button className="text-left flex-1" onClick={()=>setSelectedDate(r.date)}><p className="font-semibold">{formatDateBR(r.date)}</p><p className="text-xs" style={{color:BRAND.muted}}>{r.containers.length} CTs</p></button><button onClick={()=>deleteDay(r.date)} className="p-2 rounded-lg hover:bg-red-50 text-red-600"><Trash2 className="h-4 w-4"/></button></div></div>)}</div></CardContent></Card></aside><main className="lg:col-span-3 space-y-6">{selectedContainerReview&&currentReview?<><Card className="rounded-[1.5rem] border bg-white shadow-sm overflow-hidden" style={{borderColor:BRAND.line}}><div className="p-5 border-b" style={{borderColor:BRAND.line}}><div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4"><div><p className="uppercase tracking-[0.22em] text-xs font-semibold" style={{color:BRAND.muted}}>container selecionado</p><h2 className="text-2xl font-semibold">{selectedContainerReview.name} — {formatDateBR(currentReview.date)}</h2></div><div className="flex flex-wrap gap-2 text-sm"><InfoChip icon={Boxes} label={`${selectedTotals.boxes} caixas`}/><InfoChip icon={Package} label={`${selectedTotals.dietKg.toFixed(1)} kg dieta`}/><InfoChip icon={AlertTriangle} label={`${selectedTotals.critical} críticas`} tone="danger"/><Button variant="outline" onClick={resetSelectedContainer} className="rounded-xl text-red-700 border-red-200 hover:bg-red-50"><Trash2 className="h-4 w-4 mr-2"/>Zerar container</Button>{lastResetBackup?.reviewId===currentReview.id&&lastResetBackup?.containerId===selectedContainerId&&<Button variant="outline" onClick={undoResetSelectedContainer} className="rounded-xl"><RotateCw className="h-4 w-4 mr-2"/>Voltar opção anterior</Button>}</div></div></div><CardContent className="p-5 space-y-5"><InternalTowerLayout container={selectedContainerReview} selectedPosition={selected3DPosition} onSelectPosition={setSelected3DPosition}/><div className="grid grid-cols-1 md:grid-cols-4 gap-4"><ControlSelect label="Ventilação" value={selectedContainerReview.ventilacao} onChange={v=>updateContainerField('ventilacao',v)} options={['Manual','Automático']}/><ControlSelect label="Recirculação" value={selectedContainerReview.recirculacao} onChange={v=>updateContainerField('recirculacao',v)} options={['OFF','ON']}/><label className="space-y-1"><span className="text-sm font-semibold">Setpoint °C</span><input value={selectedContainerReview.setpoint} onChange={e=>updateContainerField('setpoint',e.target.value)} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label><label className="space-y-1"><span className="text-sm font-semibold">Observação geral CT</span><input value={selectedContainerReview.observacoesGerais} onChange={e=>updateContainerField('observacoesGerais',e.target.value)} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label></div></CardContent></Card><div className="grid grid-cols-1 md:grid-cols-2 gap-4">{selectedContainerReview.positions.map((p,idx)=><PositionCard key={p.position} p={p} idx={idx} updatePosition={updatePosition}/>)}</div></>:<Card className="rounded-[1.5rem] border bg-white shadow-sm" style={{borderColor:BRAND.line}}><CardContent className="p-8 text-center" style={{color:BRAND.muted}}>Crie ou selecione uma revisão diária.</CardContent></Card>}</main></div></>}
    {activePage==='relatorio' && <Card className="rounded-[1.5rem] border bg-white shadow-sm overflow-hidden" style={{borderColor:BRAND.line}}><CardContent className="p-5 space-y-5"><div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4"><div><p className="uppercase tracking-[0.22em] text-xs font-semibold" style={{color:BRAND.muted}}>relatório consolidado</p><h2 className="text-2xl font-semibold">Relatório do dia</h2><p className="text-sm" style={{color:BRAND.muted}}>Visualização consolidada para conferência e exportação em PDF.</p></div><Button onClick={generatePDF} disabled={!currentReview} className="rounded-xl text-white" style={{backgroundColor:BRAND.navy}}><Download className="h-4 w-4 mr-2"/>Exportar PDF</Button></div>{currentReview?<DailyReport review={currentReview} totals={dayTotals}/>:<div className="rounded-xl border p-6 text-center" style={{borderColor:BRAND.line,color:BRAND.muted}}>Crie ou selecione uma revisão diária.</div>}</CardContent></Card>}{currentReview&&<div id="daily-report-pdf" className="absolute top-0 left-[-10000px] w-[1200px] bg-white" aria-hidden="true"><DailyReport review={currentReview} totals={dayTotals}/></div>}</div></div>;
}

function PositionCard({p,idx,updatePosition}){ const total=((Number(p.caixas)||0)*(Number(p.dietaKgPorCaixa)||0)).toFixed(1); return <Card className="rounded-[1.25rem] border bg-white shadow-sm overflow-hidden" style={{borderColor:BRAND.line}}><CardContent className="p-4 space-y-3"><div className="flex items-center justify-between"><h3 className="text-lg font-semibold">Posição {p.position}</h3><div className="flex items-center gap-2"><StatusDot status={p.status}/><StatusPill status={p.status}/></div></div><div className="rounded-xl border p-3" style={{borderColor:BRAND.line,backgroundColor:BRAND.soft}}><PalletIllustration caixas={p.caixas} uso={p.uso}/></div><div className="grid grid-cols-2 md:grid-cols-3 gap-3"><label className="space-y-1"><span className="text-sm font-semibold" style={{color:BRAND.muted}}>Lote</span><input value={p.lote} onChange={e=>updatePosition(idx,'lote',e.target.value)} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label><label className="space-y-1"><span className="text-sm font-semibold" style={{color:BRAND.muted}}>Caixas</span><input type="number" min="0" max={p.uso==='Maternidade'?150:15} value={p.caixas} onChange={e=>updatePosition(idx,'caixas',e.target.value)} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label><label className="space-y-1"><span className="text-sm font-semibold" style={{color:BRAND.muted}}>Dieta</span><input value={p.dieta||''} onChange={e=>updatePosition(idx,'dieta',e.target.value.toUpperCase())} placeholder="A, B, C" className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label><label className="space-y-1"><span className="text-sm font-semibold" style={{color:BRAND.muted}}>Dieta / caixa (kg)</span><input type="number" min="0" step="0.1" value={p.dietaKgPorCaixa||''} onChange={e=>updatePosition(idx,'dietaKgPorCaixa',e.target.value)} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label></div><div className="grid grid-cols-2 gap-3"><ControlSelect label="Uso" value={p.uso} onChange={v=>updatePosition(idx,'uso',v)} options={['Produção','Colônia','Maternidade','Vazio']} muted/><ControlSelect label="Status" value={p.status} onChange={v=>updatePosition(idx,'status',v)} options={['OK','Atenção','Crítico','Vazio']} muted/></div><div className="flex flex-wrap gap-2"><UsePill uso={p.uso}/><StatusPill status={p.status}/></div><div className="rounded-xl border p-3 text-sm" style={{borderColor:BRAND.line,backgroundColor:BRAND.soft}}><div className="flex justify-between"><span style={{color:BRAND.muted}}>Dieta</span><b>{p.dieta||'-'}</b></div><div className="flex justify-between mt-1"><span style={{color:BRAND.muted}}>Dieta por caixa</span><b>{Number(p.dietaKgPorCaixa||0).toFixed(1)} kg</b></div><div className="flex justify-between mt-1"><span style={{color:BRAND.muted}}>Dieta total</span><b>{total} kg</b></div></div><label className="space-y-1 block"><span className="text-sm font-semibold" style={{color:BRAND.muted}}>Observações</span><textarea value={p.observacoes} onChange={e=>updatePosition(idx,'observacoes',e.target.value)} rows={2} className="w-full border rounded-xl px-3 py-2" style={{borderColor:BRAND.line}}/></label></CardContent></Card>; }

function ContainerYardOverview({review,selectedContainerId,onSelectContainer}){ const [hovered,setHovered]=useState(null); const [isFullscreen,setIsFullscreen]=useState(false); const [tv,setTv]=useState(false); const [panelId,setPanelId]=useState(null); if(tv) return <TVContainerWall review={review} selectedContainerId={selectedContainerId} onSelectContainer={onSelectContainer} onExit={()=>setTv(false)}/>; const panel=isFullscreen&&panelId?review.containers.find(c=>c.containerId===panelId):null; const pt=panel?computeContainerTotals(panel):null; function click(id){ onSelectContainer(id); if(isFullscreen) setPanelId(cur=>cur===id?null:id); } return <Card className={`${isFullscreen?'fixed inset-3 z-50 rounded-[1.5rem]':'rounded-[1.5rem]'} border bg-white shadow-sm overflow-hidden`} style={{borderColor:BRAND.line}}><CardContent className={`${isFullscreen?'p-5 h-full overflow-auto':'p-5'} space-y-5`}><div className="flex flex-col xl:flex-row xl:items-end xl:justify-between gap-4"><div><p className="uppercase tracking-[0.22em] text-xs font-semibold" style={{color:BRAND.muted}}>visual operacional</p><h2 className="text-2xl font-semibold">Pátio dos containers</h2><p className="text-sm" style={{color:BRAND.muted}}>Última atualização: {formatDateBR(review.date)}</p></div><div className="flex flex-wrap gap-2 text-xs"><InfoChip label={`${review.containers.length} containers`}/><InfoChip icon={Boxes} label={`${review.containers.reduce((s,c)=>s+computeContainerTotals(c).boxes,0)} caixas`}/><InfoChip icon={Package} label={`${review.containers.reduce((s,c)=>s+computeContainerTotals(c).dietKg,0).toFixed(1)} kg dieta`}/><Button variant="outline" onClick={()=>setIsFullscreen(v=>!v)} className="rounded-xl h-8 px-3">{isFullscreen?<Minimize2 className="h-4 w-4 mr-2"/>:<Maximize2 className="h-4 w-4 mr-2"/>}{isFullscreen?'Sair':'Tela cheia'}</Button><Button onClick={()=>{setTv(true);setTimeout(()=>document.getElementById('tv-container-wall')?.requestFullscreen?.().catch(()=>{}),50)}} className="rounded-xl h-8 px-3 text-white" style={{backgroundColor:BRAND.navy}}><Maximize2 className="h-4 w-4 mr-2"/>Modo TV</Button></div></div><div className={`rounded-[1.25rem] border overflow-hidden ${isFullscreen&&panel?'grid grid-cols-[minmax(0,1fr)_430px]':''}`} style={{borderColor:BRAND.line}}><div className="overflow-auto"><div className={isFullscreen?'relative h-[calc(100vh-120px)] min-h-[760px]':'relative h-[760px]'} style={{minWidth:Math.max(2100,review.containers.length*132+220),background:'linear-gradient(180deg,#EAF6FF 0%,#F8FBFD 42%,#F1F4F5 42%,#F1F4F5 100%)'}}><div className="absolute left-0 right-0 bottom-0 h-[210px]" style={{background:'linear-gradient(180deg,#E6D7BA 0%,#D7C2A0 100%)',borderTop:`1px solid ${BRAND.line}`}}/><div className="absolute left-8 top-20 w-[980px] max-w-[calc(100%-4rem)] rounded-2xl border bg-white/95 shadow-sm p-3" style={{borderColor:BRAND.line}}><div className="grid grid-cols-2 md:grid-cols-4 gap-2"><LargeInfo label="Containers" value={review.containers.length}/><LargeInfo label="Caixas totais" value={review.containers.reduce((s,c)=>s+computeContainerTotals(c).boxes,0)}/><LargeInfo label="Dieta total" value={`${review.containers.reduce((s,c)=>s+computeContainerTotals(c).dietKg,0).toFixed(1)} kg`}/><LargeInfo label="Posições" value={`${review.containers.reduce((s,c)=>s+computeContainerTotals(c).filled,0)}/${review.containers.length*8}`}/></div></div><div className="absolute left-8 bottom-[120px] flex items-end gap-3 pr-10">{review.containers.map((c,i)=><ExteriorContainer20ft key={c.containerId} container={c} index={i} active={c.containerId===selectedContainerId} hovered={c.containerId===hovered} showPopover={hovered===c.containerId} onMouseEnter={()=>setHovered(c.containerId)} onMouseLeave={()=>setHovered(null)} onClick={()=>click(c.containerId)}/>)}</div></div></div>{isFullscreen&&panel&&pt&&<FullscreenContainerPanel container={panel} totals={pt} status={pt.critical?'Crítico':pt.attention?'Atenção':pt.filled===0?'Vazio':'OK'}/>}</div></CardContent></Card>; }
function TVContainerWall({review,selectedContainerId,onSelectContainer,onExit}){ const [hovered,setHovered]=useState(null); const [clicked,setClicked]=useState(null); const panel=clicked?review.containers.find(c=>c.containerId===clicked):null; const pt=panel?computeContainerTotals(panel):null; function exit(){document.fullscreenElement&&document.exitFullscreen?.().catch(()=>{});onExit();} return <div id="tv-container-wall" className="fixed inset-0 z-[70] bg-white"><div className="h-screen flex flex-col" style={{background:'linear-gradient(180deg,#EAF6FF 0%,#F8FBFD 38%,#F1F4F5 38%,#F1F4F5 100%)'}}><div className="shrink-0 px-8 py-5 flex items-center justify-between bg-white/90 border-b" style={{borderColor:BRAND.line}}><div><p className="uppercase tracking-[0.22em] text-xs font-semibold" style={{color:BRAND.muted}}>modo tv · visual operacional</p><h1 className="text-3xl font-semibold">Pátio dos containers — {formatDateBR(review.date)}</h1></div><Button variant="outline" onClick={exit} className="rounded-xl h-10 px-4"><Minimize2 className="h-4 w-4 mr-2"/>Sair do modo TV</Button></div><div className={`flex-1 min-h-0 ${panel?'grid grid-cols-[minmax(0,1fr)_460px]':''}`}><div className="overflow-auto"><div className="relative min-h-[calc(100vh-108px)]" style={{minWidth:Math.max(3300,review.containers.length*198+320)}}><div className="absolute left-0 right-0 bottom-0 h-[260px]" style={{background:'linear-gradient(180deg,#E6D7BA 0%,#D7C2A0 100%)'}}/><div className="absolute left-12 top-8 rounded-2xl border bg-white/90 px-5 py-3 shadow-sm" style={{borderColor:BRAND.line}}><p className="text-sm font-semibold">Passe o mouse para resumo rápido. Clique em um CT para abrir/fechar painel.</p></div><div className="absolute left-12 bottom-[155px] flex items-end gap-8 pr-20">{review.containers.map((c,i)=><div key={c.containerId} style={{width:176,height:430}}><ExteriorContainer20ft container={c} index={i} active={c.containerId===clicked} hovered={c.containerId===hovered} showPopover={hovered===c.containerId} tv onMouseEnter={()=>setHovered(c.containerId)} onMouseLeave={()=>setHovered(null)} onClick={()=>{onSelectContainer(c.containerId);setClicked(cur=>cur===c.containerId?null:c.containerId)}}/></div>)}</div></div></div>{panel&&pt&&<FullscreenContainerPanel container={panel} totals={pt} status={pt.critical?'Crítico':pt.attention?'Atenção':pt.filled===0?'Vazio':'OK'}/>}</div></div></div>; }
function ExteriorContainer20ft({container,index,active,hovered,showPopover,tv=false,onMouseEnter,onMouseLeave,onClick}){ const t=computeContainerTotals(container); const status=t.critical?'Crítico':t.attention?'Atenção':t.filled===0?'Vazio':'OK'; const occ=Math.round(t.filled/8*100); const badges=getContainerUseBadges(container); const occColor=occ===100?BRAND.danger:occ>=75?BRAND.ok:occ>=40?BRAND.warn:'#E4572E'; return <div className="relative shrink-0" style={{width:tv?176:132,height:badges.length>1?(tv?470:410):(tv?430:360),zIndex:active||hovered?80:10+index}} onMouseEnter={onMouseEnter} onMouseLeave={onMouseLeave}>{showPopover&&<ContainerInfoBalloon container={container} totals={t} status={status}/>}<button onClick={onClick} className="absolute left-0 bottom-0 text-left transition-all" style={{width:tv?158:122,height:tv?360:278,transform:active||hovered?'translateY(-8px)':'translateY(0)'}}><div className={tv?(badges.length>1?'absolute -top-24 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2 w-[180px]':'absolute -top-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2 w-[180px]'):(badges.length>1?'absolute -top-20 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1.5 w-[140px]':'absolute -top-10 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1.5 w-[140px]')}>{badges.map((b,i)=><div key={i} className={tv?'rounded-full px-3 py-1.5 text-[12px] font-bold border flex items-center justify-center gap-1.5 shadow-sm min-w-[120px]':'rounded-full px-2.5 py-1 text-[10px] font-bold border flex items-center justify-center gap-1 shadow-sm min-w-[96px]'} style={{backgroundColor:b.bg,color:b.color,borderColor:BRAND.line}}><span>{b.icon}</span>{b.label}</div>)}</div><div className="absolute -bottom-3 left-2 right-1 h-5 rounded-full blur-md opacity-18" style={{backgroundColor:'#000'}}/><div className="absolute inset-0 overflow-hidden border bg-white" style={{borderColor:active?BRAND.navy:hovered?'#9CB0B8':'#C8D2D7',borderWidth:active?2:1,borderRadius:'8px 8px 4px 4px',background:'linear-gradient(90deg,#FFFFFF 0%,#F1F5F7 48%,#FFFFFF 100%)',boxShadow:active?'0 16px 30px rgba(7,53,74,.16)':hovered?'0 14px 26px rgba(7,53,74,.14)':'0 8px 16px rgba(40,50,55,.08)'}}><div className="absolute left-0 right-0 top-0 h-4" style={{backgroundColor:'#E8EDF0',borderBottom:'1px solid #D4DEE3'}}/>{Array.from({length:7}).map((_,i)=><div key={i} className="absolute top-4 bottom-5 w-[2px]" style={{left:12+i*17,backgroundColor:i%2?'#E7EDF0':'#D9E2E6'}}/>)}<div className={tv?'absolute left-3 top-9 px-2.5 py-1 text-[17px] font-black tracking-widest bg-white border rounded-sm':'absolute left-2 top-7 px-1.5 py-0.5 text-[12px] font-black tracking-widest bg-white border rounded-sm'} style={{color:BRAND.text,borderColor:'#D4DEE3'}}>{String(container.ct||container.name.replace('CT ', '')).padStart(2,'0')}</div><div className="absolute right-2 top-8 h-3 w-3 rounded-full" style={{backgroundColor:statusMeta(status).color,boxShadow:'0 0 0 3px rgba(255,255,255,.88)'}}/><div className="absolute left-0 right-0 bottom-0 h-5" style={{backgroundColor:'#F1F5F7',borderTop:'1px solid #DFE7EA'}}/></div><div className={tv?'absolute left-2 right-2 bottom-3 rounded-xl px-2.5 py-2 text-[13px] font-semibold':'absolute left-1 right-1 bottom-2 rounded-lg px-1.5 py-1 text-[10px] font-semibold'} style={{backgroundColor:'rgba(255,255,255,.97)',border:`1px solid ${BRAND.line}`,color:BRAND.muted}}><div className="flex items-center justify-between mb-1"><span>{container.name}</span><span>{t.filled}/8</span></div><div className={tv?'h-[8px] rounded-full overflow-hidden':'h-[5px] rounded-full overflow-hidden'} style={{backgroundColor:'#DCE5E9'}}><div className="h-full rounded-full" style={{width:`${occ}%`,backgroundColor:occColor}}/></div><div className={tv?'mt-1 text-[12px] text-right font-bold':'mt-0.5 text-[9px] text-right font-bold'}>{occ}%</div></div></button></div>; }
function ContainerInfoBalloon({container,totals,status}){ const occ=Math.round(totals.filled/8*100); return <div className="absolute left-1/2 -translate-x-1/2 top-0 -translate-y-[88%] w-[560px] rounded-xl border bg-white shadow-xl p-3" style={{borderColor:BRAND.line,zIndex:120}}><div className="grid grid-cols-[130px_minmax(0,1fr)] gap-3 items-start"><div><p className="text-[9px] uppercase tracking-[0.14em] font-semibold" style={{color:BRAND.muted}}>resumo</p><h4 className="text-base font-semibold">{container.name}</h4><StatusPill status={status} small/></div><div className="grid grid-cols-5 gap-1.5">{[['Caixas',totals.boxes],['Posições',`${totals.filled}/8`],['Ocupação',`${occ}%`],['Dieta',`${totals.dietKg.toFixed(1)} kg`],['Alertas',`${totals.attention}/${totals.critical}`],['Engorda',`${totals.fatteningBoxes} cx`],['Mater.',`${totals.maternityBoxes} cx`],['Vent.',container.ventilacao||'-'],['Recirc.',container.recirculacao||'-'],['Setpoint',`${container.setpoint||'-'} °C`]].map(([l,v])=><LargeInfo key={l} label={l} value={v}/>)}</div></div></div>; }
function FullscreenContainerPanel({container,totals,status}){ const ordered=[0,2,4,6,1,3,5,7].map(i=>container.positions[i]).filter(Boolean); return <aside className="border-l bg-white h-[calc(100vh-210px)] min-h-[680px] overflow-y-auto" style={{borderColor:BRAND.line}}><div className="sticky top-0 z-10 bg-white border-b p-5" style={{borderColor:BRAND.line}}><h3 className="text-2xl font-semibold">{container.name}</h3><p className="text-sm" style={{color:BRAND.muted}}>Clique novamente no CT para ocultar.</p></div><div className="p-5 space-y-5"><div className="grid grid-cols-2 gap-3"><LargeInfo label="Caixas" value={totals.boxes} fullscreen/><LargeInfo label="Posições" value={`${totals.filled}/8`} fullscreen/><LargeInfo label="Dieta" value={`${totals.dietKg.toFixed(1)} kg`} fullscreen/><LargeInfo label="Status" value={status} fullscreen/><LargeInfo label="Engorda" value={`${totals.fatteningBoxes} cx`} fullscreen/><LargeInfo label="Maternidade" value={`${totals.maternityBoxes} cx`} fullscreen/></div><div className="grid grid-cols-2 gap-3">{ordered.map(p=><BalloonTowerCard key={p.position} p={p}/>)}</div></div></aside>; }
function LargeInfo({label,value,fullscreen=false}){ return <div className="rounded-xl border bg-white px-3 py-2" style={{borderColor:BRAND.line}}><p className={`${fullscreen?'text-xs':'text-[11px]'} font-semibold leading-none`} style={{color:BRAND.muted}}>{label}</p><p className={`${fullscreen?'text-xl':'text-base'} font-bold mt-1 leading-tight truncate`} style={{color:BRAND.text}}>{value}</p></div>; }
function BalloonTowerCard({p}){ const dt=((Number(p.caixas)||0)*(Number(p.dietaKgPorCaixa)||0)).toFixed(1); return <div className="rounded-xl border bg-white p-2" style={{borderColor:BRAND.line}}><div className="flex items-center justify-between mb-2"><b>P{p.position}</b><StatusDot status={p.status}/></div><div className="rounded-lg border flex items-center justify-center h-24 mb-2 overflow-hidden px-2 py-1" style={{backgroundColor:BRAND.soft,borderColor:BRAND.line}}><PalletIllustration caixas={p.caixas} uso={p.uso} compact/></div><div className="grid grid-cols-2 gap-x-2 gap-y-1 text-[11px]"><span style={{color:BRAND.muted}}>Lote</span><b className="text-right truncate">{p.lote||'-'}</b><span style={{color:BRAND.muted}}>Cx</span><b className="text-right">{p.caixas||'-'}</b><span style={{color:BRAND.muted}}>Dieta</span><b className="text-right">{p.dieta||'-'}</b><span style={{color:BRAND.muted}}>Kg</span><b className="text-right">{dt}</b></div><div className="mt-2"><UsePill uso={p.uso} small/></div></div>; }
function InternalTowerLayout({container,selectedPosition,onSelectPosition}){ const order=[0,2,4,6,1,3,5,7]; return <div className="rounded-[1.25rem] border p-4" style={{borderColor:BRAND.line,background:'linear-gradient(180deg,#FFFFFF 0%,#F4F8FA 100%)'}}><div className="grid grid-cols-4 gap-3">{order.map(i=><InternalTowerCard key={container.positions[i].position} p={container.positions[i]} active={selectedPosition===container.positions[i].position} onClick={()=>onSelectPosition(container.positions[i].position)}/>)}</div></div>; }
function InternalTowerCard({p,active,onClick}){ const dt=((Number(p.caixas)||0)*(Number(p.dietaKgPorCaixa)||0)).toFixed(1); return <button type="button" onClick={onClick} className="rounded-xl border bg-white p-3 shadow-sm text-left transition h-full" style={{borderColor:active?BRAND.navy:BRAND.line,boxShadow:active?'0 0 0 2px rgba(7,53,74,.14)':'none'}}><div className="flex items-center justify-between mb-2"><span className="font-semibold text-sm">P{p.position}</span><StatusDot status={p.status}/></div><div className="rounded-lg border flex items-center justify-center h-32 mb-2 overflow-hidden px-2 py-2" style={{backgroundColor:BRAND.soft,borderColor:BRAND.line}}><PalletIllustration caixas={p.caixas} uso={p.uso} compact/></div><div className="grid grid-cols-2 gap-x-2 gap-y-1 text-[11px]"><span style={{color:BRAND.muted}}>Lote</span><b className="text-right truncate">{p.lote||'-'}</b><span style={{color:BRAND.muted}}>Cx</span><b className="text-right">{p.caixas||'-'}</b><span style={{color:BRAND.muted}}>Dieta</span><b className="text-right truncate">{p.dieta||'-'}</b><span style={{color:BRAND.muted}}>Kg</span><b className="text-right">{dt}</b></div><div className="mt-2"><UsePill uso={p.uso} small/></div></button>; }
function PalletIllustration({caixas,uso='Produção',compact=false}){ const count=Math.max(0,Number(caixas)||0); const isMat=uso==='Maternidade'; const levels=isMat?Math.ceil(count/10):count; const visible=Math.min(levels,compact?8:15); const stackWidth=compact?56:92; const boxHeight=compact?7:8; return <div className="w-full h-full flex items-end justify-center overflow-hidden"><div className="relative flex flex-col items-center justify-end" style={{width:stackWidth,height:compact?116:176}}><div className="flex flex-col-reverse items-center justify-start overflow-hidden" style={{width:stackWidth,maxHeight:compact?86:150,gap:compact?2:3}}><PalletBase compact={compact} fit/>{visible===0?<div className="rounded-lg border border-dashed flex items-center justify-center text-[10px] w-full" style={{color:BRAND.empty,borderColor:'#C9D3D8',height:compact?34:46}}>vazio</div>:Array.from({length:visible}).map((_,i)=>isMat?<MaternityLevelMini key={i} compact={compact} height={boxHeight}/>:<RealBox key={i} compact={compact} fit height={boxHeight}/>)}</div>{count>0&&<div className="absolute -top-1 right-0 rounded-full px-1.5 py-0.5 text-[10px] font-bold border bg-white" style={{color:BRAND.navy,borderColor:BRAND.line}}>{count} cx</div>}</div></div>; }
function MaternityLevelMini({compact=false,height=5}){ return <div className="grid grid-cols-10 w-full" style={{gap:compact?1:2,height}}>{Array.from({length:10}).map((_,i)=><div key={i} className="rounded-[2px]" style={{background:'linear-gradient(180deg,#293138 0%,#11181D 100%)'}}/>)}</div>; }
function RealBox({compact=false,fit=false,height}){ const h=height||(compact?8:10); const side=compact?6:9; return <div className={`relative mx-auto ${fit?'w-full':compact?'w-16':'w-24'} rounded-[3px] overflow-visible`} style={{height:h,filter:'drop-shadow(0 1px 1px rgba(0,0,0,.22))'}}><div className="absolute inset-x-0 bottom-0 rounded-[3px] overflow-hidden" style={{height:h,background:`linear-gradient(90deg,${BRAND.crateBlue} 0px,${BRAND.crateBlue} ${side}px,${BRAND.crateBlack} ${side}px,${BRAND.crateBlack} calc(100% - ${side}px),${BRAND.crateBlue} calc(100% - ${side}px),${BRAND.crateBlue} 100%)`,border:'1px solid rgba(0,0,0,.20)',boxShadow:'inset 0 -2px 0 rgba(0,0,0,.18)'}}/><div className="absolute left-[4px] right-[4px] rounded-t-[3px]" style={{top:-3,height:4,background:'linear-gradient(180deg,#3B4850 0%,#252D33 100%)',transform:'skewX(-18deg)',transformOrigin:'bottom left'}}/></div>; }
function PalletBase({compact=false,fit=false}){ return <div className={`${fit?'w-full':compact?'w-20':'w-28'} mt-1 mx-auto shrink-0`}><div className={`${compact?'h-[5px]':'h-[6px]'} rounded-sm`} style={{backgroundColor:BRAND.pallet}}/><div className="grid grid-cols-3 gap-1 mt-1"><div className={`${compact?'h-[6px]':'h-[8px]'} rounded-sm`} style={{backgroundColor:BRAND.palletDark}}/><div className={`${compact?'h-[6px]':'h-[8px]'} rounded-sm`} style={{backgroundColor:BRAND.palletDark}}/><div className={`${compact?'h-[6px]':'h-[8px]'} rounded-sm`} style={{backgroundColor:BRAND.palletDark}}/></div></div>; }
function DailyReport({review,totals}){ return <section id="daily-report" className="bg-white rounded-[1.5rem] border shadow-sm p-6 md:p-8 space-y-8 print:shadow-none" style={{borderColor:BRAND.line}}><div className="flex flex-col md:flex-row justify-between gap-4 border-b pb-5" style={{borderColor:BRAND.line}}><div className="space-y-3"><BuzzLogo/><div><h2 className="text-2xl font-semibold">Relatório Diário Consolidado — Containers BSF</h2><p style={{color:BRAND.muted}}>Controle geral dos containers de criação - BSF.</p></div></div><div className="text-right"><p className="text-sm" style={{color:BRAND.muted}}>Data operacional</p><p className="text-2xl font-semibold" style={{color:BRAND.navy}}>{formatDateBR(review.date)}</p><p className="text-sm mt-1" style={{color:BRAND.muted}}>Responsável: {review.responsavel||'-'}</p></div></div><div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-8 gap-3"><Metric label="Containers" value={review.containers.length}/><Metric label="Ocupação" value={`${totals.occupancyRate}%`} icon={Package} tone="ok" sublabel={`${totals.filledPositions}/${totals.totalPositions} posições`}/><Metric label="Total de caixas" value={totals.boxes} icon={Boxes}/><Metric label="Dieta em bioconversão" value={`${totals.dietKg.toFixed(1)} kg`} icon={Package}/><Metric label="Caixas engorda" value={totals.fatteningBoxes} icon={Boxes}/><Metric label="Caixas maternidade" value={totals.maternityBoxes} icon={Boxes}/><Metric label="Atenção" value={totals.attention} icon={AlertTriangle} tone="warn"/><Metric label="Críticas" value={totals.critical} icon={AlertTriangle} tone="danger"/></div><div className="space-y-6">{review.containers.map(c=>{ const ct=computeContainerTotals(c); return <div key={c.containerId} className="break-inside-avoid border rounded-[1.25rem] p-4 space-y-4" style={{borderColor:BRAND.line}}><div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3"><h3 className="text-xl font-semibold">{c.name}</h3><div className="flex flex-wrap gap-2 text-xs"><InfoChip icon={Wind} label={`Ventilação: ${c.ventilacao}`}/><InfoChip label={`Recirc.: ${c.recirculacao}`}/><InfoChip label={`Setpoint: ${c.setpoint||'-'} °C`}/><InfoChip icon={Boxes} label={`${ct.boxes} caixas`}/><InfoChip icon={Package} label={`${ct.dietKg.toFixed(1)} kg dieta`}/></div></div><table className="w-full text-xs border rounded-xl overflow-hidden" style={{borderColor:BRAND.line}}><thead style={{backgroundColor:BRAND.soft}}><tr>{['Pos.','Lote','Dieta','Caixas','Dieta/caixa','Dieta total','Uso','Status','Observações'].map(h=><th key={h} className="p-2 text-left">{h}</th>)}</tr></thead><tbody>{c.positions.map(p=><tr key={p.position} className="border-t" style={{borderColor:BRAND.line}}><td className="p-2 font-semibold">{p.position}</td><td className="p-2">{p.lote||'-'}</td><td className="p-2">{p.dieta||'-'}</td><td className="p-2">{p.caixas||'-'}</td><td className="p-2">{p.dietaKgPorCaixa?`${Number(p.dietaKgPorCaixa).toFixed(1)} kg`:'-'}</td><td className="p-2">{((Number(p.caixas)||0)*(Number(p.dietaKgPorCaixa)||0)).toFixed(1)} kg</td><td className="p-2"><UsePill uso={p.uso} small/></td><td className="p-2"><StatusPill status={p.status} small/></td><td className="p-2">{p.observacoes||'-'}</td></tr>)}</tbody></table>{c.observacoesGerais&&<div className="text-sm rounded-xl p-3" style={{backgroundColor:BRAND.soft}}><b>Observações gerais:</b> {c.observacoesGerais}</div>}</div>})}</div></section>; }
